import numpy as np

class Layer:
    def __init__(self, input_size, output_size, activation):
        self.weights = np.random.randn(input_size, output_size) * 0.01
        self.biases = np.zeros((1, output_size))
        self.activation = activation
        self.input = None
        self.output = None

    def forward(self, input_data):
        self.input = input_data
        z = np.dot(input_data, self.weights) + self.biases
        self.output = self.activation(z)
        return self.output

    def backward(self, output_gradient, learning_rate):
        activation_gradient = self.activation_derivative(self.output)
        z_gradient = output_gradient * activation_gradient
        self.weights_gradient = np.dot(self.input.T, z_gradient)
        self.biases_gradient = np.sum(z_gradient, axis=0, keepdims=True)
        input_gradient = np.dot(z_gradient, self.weights.T)

        self.weights -= learning_rate * self.weights_gradient
        self.biases -= learning_rate * self.biases_gradient
        return input_gradient

    def activation_derivative(self, output):
        if self.activation == self.sigmoid:
            return output * (1 - output)
        elif self.activation == self.relu:
            return np.where(output > 0, 1, 0)
        elif self.activation == self.tanh:
            return 1 - np.square(output)
        else:
            raise ValueError("Unsupported activation function")

    @staticmethod
    def sigmoid(x):
        return 1 / (1 + np.exp(-x))

    @staticmethod
    def relu(x):
        return np.maximum(0, x)

    @staticmethod
    def tanh(x):
        return np.tanh(x)

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers, activations):
        self.layers = []
        layer_sizes = [input_size] + hidden_layers + [output_size]
        for i in range(len(layer_sizes) - 1):
            self.layers.append(Layer(layer_sizes[i], layer_sizes[i + 1], activations[i]))

    def forward(self, input_data):
        for layer in self.layers:
            input_data = layer.forward(input_data)
        return input_data

    def backward(self, output_gradient, learning_rate):
        for layer in reversed(self.layers):
            output_gradient = layer.backward(output_gradient, learning_rate)

    def train(self, X, y, epochs, learning_rate):
        for epoch in range(epochs):
            output = self.forward(X)
            loss = self.loss(output, y)
            output_gradient = self.loss_derivative(output, y)
            self.backward(output_gradient, learning_rate)
            if epoch % 100 == 0:
                print(f'Epoch {epoch}, Loss: {loss}')

    @staticmethod
    def loss(predictions, targets):
        return np.mean(np.square(predictions - targets))

    @staticmethod
    def loss_derivative(predictions, targets):
        return 2 * (predictions - targets) / targets.size

