import numpy as np

class NeuralNetwork:
    def __init__(self, layers):
        self.layers = layers
        self.weights = []
        self.biases = []
        self.initialize_parameters()

    def initialize_parameters(self):
        for i in range(len(self.layers) - 1):
            weight = np.random.randn(self.layers[i], self.layers[i + 1]) * 0.01
            bias = np.zeros((1, self.layers[i + 1]))
            self.weights.append(weight)
            self.biases.append(bias)

    def activation(self, z, activation_type='relu'):
        if activation_type == 'relu':
            return np.maximum(0, z)
        elif activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-z))
        elif activation_type == 'tanh':
            return np.tanh(z)
        else:
            raise ValueError("Unsupported activation type")

    def activation_derivative(self, z, activation_type='relu'):
        if activation_type == 'relu':
            return (z > 0).astype(float)
        elif activation_type == 'sigmoid':
            sig = self.activation(z, 'sigmoid')
            return sig * (1 - sig)
        elif activation_type == 'tanh':
            return 1 - np.tanh(z) ** 2
        else:
            raise ValueError("Unsupported activation type")

    def forward_propagation(self, X):
        self.a = [X]
        for i in range(len(self.weights)):
            z = np.dot(self.a[i], self.weights[i]) + self.biases[i]
            a = self.activation(z)
            self.a.append(a)
        return self.a[-1]

    def compute_loss(self, y_true, y_pred, loss_type='mse'):
        if loss_type == 'mse':
            return np.mean((y_true - y_pred) ** 2)
        elif loss_type == 'binary_crossentropy':
            return -np.mean(y_true * np.log(y_pred + 1e-15) + (1 - y_true) * np.log(1 - y_pred + 1e-15))
        else:
            raise ValueError("Unsupported loss type")

    def backward_propagation(self, y_true, loss_type='mse'):
        m = y_true.shape[0]
        self.dA = self.a[-1] - y_true
        for i in reversed(range(len(self.weights))):
            dZ = self.dA * self.activation_derivative(self.a[i + 1])
            self.dW = np.dot(self.a[i].T, dZ) / m
            self.dB = np.sum(dZ, axis=0, keepdims=True) / m
            self.dA = np.dot(dZ, self.weights[i].T)
            self.weights[i] -= 0.01 * self.dW
            self.biases[i] -= 0.01 * self.dB

    def train(self, X, y, epochs=1000, loss_type='mse'):
        for epoch in range(epochs):
            y_pred = self.forward_propagation(X)
            loss = self.compute_loss(y, y_pred, loss_type)
            self.backward_propagation(y, loss_type)
            if epoch % 100 == 0:
                print(f'Epoch {epoch}, Loss: {loss}')

