import numpy as np

class NeuralNetwork:
    def __init__(self, layers):
        self.layers = layers
        self.weights = []
        self.biases = []
        self.initialize_parameters()

    def initialize_parameters(self):
        for i in range(len(self.layers) - 1):
            weight = np.random.randn(self.layers[i], self.layers[i + 1]) * 0.01
            bias = np.zeros((1, self.layers[i + 1]))
            self.weights.append(weight)
            self.biases.append(bias)

    def activation(self, z, activation_type='relu'):
        if activation_type == 'relu':
            return np.maximum(0, z)
        elif activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-z))
        elif activation_type == 'tanh':
            return np.tanh(z)
        else:
            return z  # Linear activation

    def activation_derivative(self, z, activation_type='relu'):
        if activation_type == 'relu':
            return (z > 0).astype(float)
        elif activation_type == 'sigmoid':
            sig = self.activation(z, 'sigmoid')
            return sig * (1 - sig)
        elif activation_type == 'tanh':
            return 1 - np.tanh(z) ** 2
        else:
            return np.ones_like(z)  # Derivative of linear is 1

    def forward_propagation(self, X):
        self.a = [X]
        for i in range(len(self.layers) - 1):
            z = np.dot(self.a[i], self.weights[i]) + self.biases[i]
            a = self.activation(z)
            self.a.append(a)
        return self.a[-1]

    def backward_propagation(self, X, y, activation_type='relu'):
        m = y.shape[0]
        self.d_weights = []
        self.d_biases = []

        # Output layer error
        output_error = self.a[-1] - y
        for i in reversed(range(len(self.layers) - 1)):
            if i == len(self.layers) - 2:  # Last layer
                delta = output_error * self.activation_derivative(self.a[i + 1], activation_type)
            else:
                delta = np.dot(delta, self.weights[i + 1].T) * self.activation_derivative(self.a[i + 1], activation_type)

            self.d_weights.append(np.dot(self.a[i].T, delta) / m)
            self.d_biases.append(np.sum(delta, axis=0, keepdims=True) / m)

        self.d_weights.reverse()
        self.d_biases.reverse()

    def update_parameters(self, learning_rate):
        for i in range(len(self.layers) - 1):
            self.weights[i] -= learning_rate * self.d_weights[i]
            self.biases[i] -= learning_rate * self.d_biases[i]

    def train(self, X, y, epochs, learning_rate, activation_type='relu'):
        for epoch in range(epochs):
            self.forward_propagation(X)
            self.backward_propagation(X, y, activation_type)
            self.update_parameters(learning_rate)

